PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(MAX(?duration) AS ?max_duration) WHERE {
  VALUES ?series {
    wd:Q56692089 wd:Q14870260 wd:Q3511178
  }
  ?game wdt:P1548 ?series .
  {
    ?game wdt:P1095 wd:Q15083
  } UNION {
    ?game wdt:P1591 wd:Q15083
  }
  ?game wdt:P5204 ?duration .
}

